  p.rect(3, 12, 10, 1, darken(P.wood, 0.4));  // ground shadow line
  p.vline(9, 12, 4, darken(P.wood, 0.45));    // left iron strap
  p.vline(9, 12, 11, darken(P.wood, 0.45));   // right iron strap
  p.px(4, 12, P.glint); p.px(11, 12, P.steelL);

  // open lid — angled upward, lighter top facing the light
  p.gradV(2, 6, 12, 3, P.woodL, P.wood);
  p.hline(2, 13, 6, lighten(P.woodL, 0.28));  // bright top edge of lid
  p.rect(3, 4, 10, 2, darken(P.wood, 0.3));   // inner lid shadow
  p.px(2, 6, P.rim); p.px(3, 5, P.rim);       // top-left rim catch

  // the hoard — stacked coins with specular glints
  p.ellipse(6, 5, 1.7, 1.4, P.goldD); p.ellipse(6, 5, 1.3, 1.0, P.gold);
  p.ellipse(9, 6, 1.8, 1.4, P.gold);  p.ellipse(9, 6, 1.2, 1.0, P.goldL);
  p.ellipse(11, 5, 1.5, 1.2, P.goldD);p.ellipse(11, 5, 1.0, 0.8, P.gold);
  p.px(6, 4, P.goldL); p.px(11, 4, P.goldL); p.px(9, 5, P.holyL);
  // a single big coin set into the open chest mouth
  p.rect(7, 8, 2, 2, P.goldD); p.px(8, 8, P.goldL); p.px(7, 9, P.gold);

  // kira sparkles rising from the treasure
  p.star4(4, 3, 2, P.holyL, P.glint);
  p.sparkle(13, 4, P.gold, 1);
  p.px(12, 7, P.glint);
