// ---- additive ambient variants (optional decor; do not replace originals) ---
// 魂晶汲泉 (idle pulse) — alt animated shardwell used by ambient galleries.
// Additive: original facility_g_camp_shardwell icon above is untouched.
defineAnim('facility_g_camp_shardwell_pulse', 16, 16, 4, (p, f) => {
  const phase = f / 4;
  panel(p, P.shardD);
  const pulse = 0.34 + 0.16 * Math.sin(phase * Math.PI * 2);
  p.glow(8, 6, 6, P.shard, pulse, 5);
  p.softShadow(8, 14, 6, 1.3, 0.32);

  // well rim
  p.gradV(3, 11, 10, 3, P.gray2, darken(P.gray2, 0.32));
  p.hline(3, 12, 11, P.gray3);
  p.rect(3, 13, 10, 1, darken(P.gray2, 0.4));

  // glowing pool
  p.ellipse(8, 11, 3.6, 1.4, darken(P.shard, 0.4));
  p.ellipse(8, 11, 2.6, 0.9, P.shardD);

  // floating shard
  p.ellipse(8, 6, 2.4, 4, darken(P.shard, 0.22));
  p.ellipse(8, 6, 1.5, 3.2, P.shard);
  p.vline(3, 8, 8, P.shardL);
  p.px(7, 4, P.white);

  // pulsing aura ring + drifting mote
  p.aura(8, 6, 4, P.shardL, phase, 2);
  const my = 10 - f;              // mote rises across frames
  p.px(11, my, P.shardL);
  p.outline(P.ink);
}, { fps: 6, loop: true, anchor: [8, 8] });
